module RefModule(
    input clk,
    input reset,
    input signal,
    output reg [31:0] output_reg
);reg obf_signal_d;
always @(posedge clk) begin
    obf_signal_d <= signal;
    if (reset) begin
        output_reg <= 1;
    end else if (obf_signal_d && !signal) begin
        output_reg <= {32{1'b1}};
    end
end

endmodule
